    tien2: '[tien2]:=[so_luong]*[gia2]',
    tien2_tg: '[tien2]:=[tien_nt2]*[$ty_gia]',
    ck_nt: '[ck_nt]:=[tien_nt2]*[tl_ck]/100',
    ck_tg: '[ck]:=[ck_nt]*[$ty_gia]',
    ck_tl: '[ck]:=[tien2]*[tl_ck]/100',

    &DetailTaxFomula;

    t_so_luong: ['t_so_luong', 'so_luong'],
    t_tien_nt: ['t_tien_nt', 'tien_nt'],
    t_tien: ['t_tien', 'tien'],
    t_tien_nt2: ['t_tien_nt2', '[tien_nt2] - [ck_nt]', '[km_yn] == 0'],
    t_tien2: ['t_tien2', '[tien2] - [ck]', '[km_yn] == 0'],
    t_tien_km_nt: ['t_tien_km_nt', 'tien_nt2', '[km_yn] != 0'],
    t_tien_km: ['t_tien_km', 'tien2', '[km_yn] != 0'],
    t_tien_km_ct_nt: ['t_tien_km_ct_nt', 'tien_nt2', '(([km_yn] == 2) || ([km_yn] == 3))'],
    t_tien_km_ct: ['t_tien_km_ct', 'tien2', '(([km_yn] == 2) || ([km_yn] == 3))'],
    t_tc_tien_nt2: ['t_tc_tien_nt2', 'tien_nt2'],
    t_tc_tien2: ['t_tc_tien2', 'tien2'],
    t_ck_nt: ['t_ck_nt', 'ck_nt'],
    t_ck: ['t_ck', 'ck'],
    t_km_nt: '[t_km_nt]:=[t_tien_km_nt]+[t_thue_km_nt]',
    t_km: '[t_km]:=[t_tien_km]+[t_thue_km]',
&EnvironmentTaxDetailArray;
    t_thue: '[t_thue]:=[t_tien2]*[thue_suat]/100',
    t_thue_nt: '[t_thue_nt]:=[t_tien_nt2]*[thue_suat]/100',
    t_thue_km: '[t_thue_km]:=[t_tien_km_ct]*[thue_suat]/100',
    t_thue_km_nt: '[t_thue_km_nt]:=[t_tien_km_ct_nt]*[thue_suat]/100',
    t_tt: '[t_tt]:=[t_tien2]+[t_thue]',
    t_tt_nt: '[t_tt_nt]:=[t_tien_nt2]+[t_thue_nt]'
  };
  g.$h = [['voucherCode', 'String', g._voucherCode], 'ma_kh', 'ngay_lct', 'ma_nt', 'ma_dvcs'];
