function onChange$GridVoucherDetail$Promotion(o) {
  var g = o.grid, row = o.row, item = g._getItem(row, g._getColumnOrder('ma_vt')), v = g._getItemValue(row, g._getColumnOrder('km_yn'));
  if (&DetailTaxPromotionValidConditional;(!item._saleAccount) || (!item._COSGAccount) || (!item._promotionAccount)) g.request(o, 'Promotion', 'Promotion', ['ma_vt']);
  if (v == '0') {
    g.setItemGridBehavior(o, [['tk_dt', item._saleAccount, ['', item._saleType], null],['tk_gv', item._COSGAccount, ['', item._COSGType], null],['tk_cpbh', '', '', null]]);
  } else {
    g.setItemGridBehavior(o, [['tk_dt', item._promotionAccount, ['', item._promotionType], null],['tk_gv', item._promotionAccount, ['', item._promotionType], null]]);
    if (v == '1') g.setItemGridBehavior(o, [['tk_cpbh', '', '', null]]);
      else g.setItemGridBehavior(o, [['tk_cpbh', item._promotionAccount, ['', item._promotionType], null]]);
  }
  &DetailTaxPromotionValid;
}
