function onChange$GridVoucherDetail$(sender, eventArgs) {
  var o = eventArgs.get_object(), g = o.grid, f = g.get_element().parentForm, name = o.field.Name;
  switch (name) {
    case 'so_luong':
      g.validExpression(o, [g.$a.tien_nt, g.$a.tien, g.$a.tien_nt2, g.$a.ck_nt, g.$a.AmountFormula, g.$a.ck_tl&EnvironmentTaxDetailChangeQuatity;], [g.$a.t_so_luong, g.$a.t_tien_nt, g.$a.t_tien&EnvironmentTaxDetailChangeQuatityTotal;], null, 'gia_nt2');
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      onChange$GridVoucherDetail$Discount(o);
      break;
    case 'km_yn':
      g.request(o, 'Promotion', 'Promotion', ['ma_vt'])
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      on$GridVoucherDetail$PromotionChange(o, g, f);
      break;
    case 'gia_nt2':
      g.executeExpression(o, [g.$a.gia2, g.$a.tien_nt2, g.$a.AmountFormula, g.$a.ck_nt, g.$a.ck_tl]);
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      onChange$GridVoucherDetail$Discount(o);
      g.live(o, 'tien_nt2');
      break;
    case 'gia2':
      &DetailTaxValidSalesPrice;
      break;
    case 'tien_nt2':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt2_sl, g.$a.gia2]);
      g.executeExpression(o, [g.$a.tien2_tg, g.$a.ck_nt, g.$a.ck_tl]);
      on$GridVoucherDetail$AmountChange(o, g, f);
      on$GridVoucherDetail$TaxChange(o, g, f);
      onChange$GridVoucherDetail$Discount(o);
      g.live(o, 'ck_nt');
      break;
    case 'tien2':
      if (f._calPrice) g.validExpression(o, [g.$a.gia2_sl]);
      &DetailTaxValidSalesAmount;
      break;
    case 'tl_ck':
      g.validExpression(o, [g.$a.ck_nt, g.$a.ck_tl], [g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_ck_nt, g.$a.t_ck], null, 'ck_nt');
      on$GridVoucherDetail$TaxChange(o, g, f);
      onChange$GridVoucherDetail$Discount(o);
      break;
    case 'ck_nt':
      g.validExpression(o, [g.$a.ck_tg], [g.$a.t_tien_nt2, g.$a.t_tien2, g.$a.t_ck_nt, g.$a.t_ck]);
      on$GridVoucherDetail$TaxChange(o, g, f);
      onChange$GridVoucherDetail$Discount(o);
      break;
    case 'ck':
      &DetailTaxValidDiscount;
      break;
    case 'gia_nt':
      g.validExpression(o, [g.$a.gia, g.$a.tien_nt, g.$a.tien], [g.$a.t_tien_nt, g.$a.t_tien], null, 'tien_nt');
      break;
    case 'gia':
      g.validExpression(o, [g.$a.tien], [g.$a.t_tien], null, 'tien');
      break;
    case 'tien_nt':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_nt_sl, g.$a.gia]);
      g.validExpression(o, [g.$a.tien_tg], [g.$a.t_tien_nt, g.$a.t_tien]);
      break;
    case 'tien':
      if (f._calPrice) g.validExpression(o, [g.$a.gia_sl]);
      g.executeAggregate([g.$a.t_tien]);
      break;
    &DetailTaxOnchange;
    &EnvironmentTaxDetailChange;
    default:
      break;
  }
}
function on$GridVoucherDetail$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender, f = g.get_element().parentForm, l = f.getItemValue('loai_ct'), v = (!f._$inStockType) && (l == 6);
  switch (action) {&ScriptCheckGridAction;
    case 'AfterRemoveRow':
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'AfterInsertRow':
      &DetailTaxGridAfterInsertRow;
      break;
    case 'AfterCloneRow':
      g.setItemFieldValue('stt_rec0', e.type.Value, '');
      on$GridVoucherDetail$RowChange(g, f);
      break;
    case 'Check':
      if (v && !(g.validRowExpression('hd_so', '[stt_rec_hd] == ""'))) break;

      if (!(g.validRowExpression('so_luong', '([gia_ton] != 3) || ([gia_ton] == 3 && [so_luong] != 0)'))) break;
      if (g._tracked$Lot && !(g.validRowExpression('ma_lo', '(![lo_yn]) || ([ma_lo] != "")'))) break;
      if (g._tracked$Location && !(g.validRowExpression('ma_vi_tri', '(![vi_tri_yn]) || ([ma_vi_tri] != "")'))) break;
      if (!(g.validRowExpression('tk_cpbh', '([km_yn] == 0) || ([km_yn] == 1) || ([tk_cpbh] != "")'))) break;
      &EnvironmentTaxCheckPromotion;
      &EnvironmentTaxCheck;
      &DetailTaxExecuteCommandCheck;
      break;
    case 'Retrieve':
      if (f._action == 'View') break;
      if (!f.validFields('ma_kh, ngay_lct')) break;
      &ScriptGridShowFlowSRDetail;
      break;
    case 'Copying':
      var fields = 'hd_so, hd_ln, px_so, px_ln, stt_rec_dh, stt_rec0dh, stt_rec_px, stt_rec0px, stt_rec_hd, stt_rec0hd';
      &ScriptWhenTransactionEmptyField;
      if (fields != '') set$Voucher$EmptyExternalField(g, fields);
      break;
    default:
      break;
  }
}
