        ['tk_vt', result[4].Value, '', true],
        ['tk_dt', [result[5].Value, '[km_yn] == "0"'], ['', result[6].Value], true],
        ['tk_gv', [result[7].Value, '[km_yn] == "0"'], ['', result[8].Value], true],
        ['tk_cpbh', [result[9].Value, '(([km_yn] == 2) || ([km_yn] == 3))'], ['', result[10].Value], true],
        ['gia_ton', result[11].Value, null, null],
        ['vi_tri_yn', [result[12].Value, t], null, null],
        ['lo_yn', result[13].Value, null, null],
        ['tk_ck', [result[14].Value, '[ck_nt] > 0'], ['', result[15].Value], true]&EnvironmentTaxDetailResponseItem;
      ]);
      o._discountAccount = result[14].Value;
